import React, { useRef, useEffect, useState } from "react";
import MessageBubble from "./MessageBubble";
import socket from "../socket";

export default function ChatWindow({ chat, username, typingUser, search }) {
  const [message, setMessage] = useState("");
  const bottomRef = useRef(null);

  const sendMessage = () => {
    if (message.trim()) {
      socket.emit("send-message", { text: message });
      setMessage("");
    }
  };

  const handleTyping = () => {
    socket.emit("typing", username);
  };

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  return (
    <div className="flex-1 flex flex-col p-6">
      <h2 className="text-2xl font-bold text-gray-800 mb-2">Chat Room</h2>

      <div className="bg-white h-[80vh] overflow-y-auto p-4 rounded shadow-inner flex-1">
        {chat.map((msg, i) => (
          <MessageBubble
            key={i}
            sender={msg.sender}
            text={msg.text}
            time={msg.time}
            isSelf={msg.sender === username}
          />
        ))}
        {typingUser && (
          <div className="text-sm text-gray-500 italic mb-2">
            {typingUser} is typing...
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <div className="mt-4 flex gap-2">
        <input
          className="flex-1 border p-2 rounded shadow-sm"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          onKeyDown={handleTyping}
          placeholder="Type a message..."
        />
        <button
          onClick={sendMessage}
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          Send
        </button>
      </div>
    </div>
  );
}
